-- 1. Insert Topics first
INSERT INTO public.topics (id, name, description) VALUES
(1, 'Arrays & Hashing', 'Questions that involve arrays, hash maps, and hash sets.'),
(2, 'Two Pointers', 'Questions that are efficiently solved using two pointers.'),
(3, 'Stack', 'Questions that involve stack data structure (LIFO).'),
(4, 'Linked Lists', 'Questions involving linked list traversal, manipulation, and fast/slow pointers.'),
(5, 'Monotonic Stacks', 'Questions involving stacks that maintain a monotonically increasing or decreasing order.'),
(6, 'Queues / Deque', 'Questions utilizing queues and double-ended queues for sliding window patterns.'),
(7, 'Binary Trees', 'Questions focusing on binary tree traversal (DFS, BFS), recursion, and structures.'),
(8, 'Binary Search Trees', 'Questions relying on the properties of a BST (left <= root <= right).')
ON CONFLICT (id) DO NOTHING;

-- 2. Insert Questions
INSERT INTO public.questions (title, topic_id, difficulty, description, test_cases, starter_code) VALUES
(
    'Two Sum',
    1,
    'Easy',
    'Given an array of integers `nums` and an integer `target`, return indices of the two numbers such that they add up to `target`.',
    '[
        {"input": "nums = [2,7,11,15], target = 9", "expected_output": "[0,1]"},
        {"input": "nums = [3,2,4], target = 6", "expected_output": "[1,2]"},
        {"input": "nums = [3,3], target = 6", "expected_output": "[0,1]"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <unordered_map>\n#include <string>\n#include <sstream>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<int> twoSum(vector<int>& nums, int target) {\n        // Write your code here\n        return {};\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    vector<int> nums;\n    stringstream ss(arrayStr);\n    string token;\n    while (getline(ss, token, '','')) {\n        nums.push_back(stoi(token));\n    }\n    size_t targetPos = input.find(\"target = \");\n    int target = stoi(input.substr(targetPos + 9));\n    Solution sol;\n    vector<int> result = sol.twoSum(nums, target);\n    if (result.size() == 2) {\n        cout << \"[\" << result[0] << \",\" << result[1] << \"]\" << endl;\n    } else {\n        cout << \"[]\" << endl;\n    }\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nvar twoSum = function(nums, target) {\n    // Write your code here\n    return [];\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const numsStrMatch = input.match(/nums = (\\[.*?\\])/);\n        const targetStrMatch = input.match(/target = (-?\\d+)/);\n        if(!numsStrMatch || !targetStrMatch) return;\n        const nums = JSON.parse(numsStrMatch[1]);\n        const target = parseInt(targetStrMatch[1]);\n        const result = twoSum(nums, target);\n        console.log(JSON.stringify(result));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Valid Parentheses',
    3,
    'Easy',
    'Given a string `s` containing just the characters `''(''`, `'')''`, determine if the input string is valid.',
    '[
        {"input": "s = \"()\"", "expected_output": "true"},
        {"input": "s = \"()[]{}\"", "expected_output": "true"},
        {"input": "s = \"(]\"", "expected_output": "false"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <string>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    bool isValid(string s) {\n        // Write your code here\n        return false;\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t quoteStart = input.find(''\"'');\n    size_t quoteEnd = input.rfind(''\"'');\n    string s = \"\";\n    if (quoteStart != string::npos && quoteEnd != string::npos && quoteStart < quoteEnd) {\n        s = input.substr(quoteStart + 1, quoteEnd - quoteStart - 1);\n    }\n    Solution sol;\n    bool result = sol.isValid(s);\n    cout << (result ? \"true\" : \"false\") << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nvar isValid = function(s) {\n    // Write your code here\n    return false;\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/s = \"(.*)\"/);\n        if(!match) return;\n        const s = match[1];\n        const result = isValid(s);\n        console.log(result ? \"true\" : \"false\");\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Container With Most Water',
    2,
    'Medium',
    'You are given an integer array `height`. Find two lines that together with the x-axis form a container, such that the container contains the most water.',
    '[
        {"input": "height = [1,8,6,2,5,4,8,3,7]", "expected_output": "49"},
        {"input": "height = [1,1]", "expected_output": "1"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n#include <algorithm>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    int maxArea(vector<int>& height) {\n        // Write your code here\n        return 0;\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    vector<int> height;\n    if (!arrayStr.empty()) {\n        stringstream ss(arrayStr);\n        string token;\n        while (getline(ss, token, '','')) {\n            height.push_back(stoi(token));\n        }\n    }\n    Solution sol;\n    int result = sol.maxArea(height);\n    cout << result << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nvar maxArea = function(height) {\n    // Write your code here\n    return 0;\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/height = (\\[.*?\\])/);\n        if(!match) return;\n        const height = JSON.parse(match[1]);\n        const result = maxArea(height);\n        console.log(result);\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    '3Sum',
    1,
    'Medium',
    'Given an integer array nums, return all the triplets [nums[i], nums[j], nums[k]] such that i != j, i != k, and j != k, and nums[i] + nums[j] + nums[k] == 0.',
    '[
        {"input": "nums = [-1,0,1,2,-1,-4]", "expected_output": "[[-1,-1,2],[-1,0,1]]"},
        {"input": "nums = [0,1,1]", "expected_output": "[]"},
        {"input": "nums = [0,0,0]", "expected_output": "[[0,0,0]]"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n#include <algorithm>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<vector<int>> threeSum(vector<int>& nums) {\n        // Write your code here\n        return {};\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    vector<int> nums;\n    if (!arrayStr.empty()) {\n        stringstream ss(arrayStr);\n        string token;\n        while (getline(ss, token, '','')) {\n            nums.push_back(stoi(token));\n        }\n    }\n    Solution sol;\n    vector<vector<int>> result = sol.threeSum(nums);\n    cout << \"[\";\n    for (size_t i = 0; i < result.size(); ++i) {\n        cout << \"[\";\n        for (size_t j = 0; j < result[i].size(); ++j) {\n            cout << result[i][j] << (j == result[i].size() - 1 ? \"\" : \",\");\n        }\n        cout << \"]\" << (i == result.size() - 1 ? \"\" : \",\");\n    }\n    cout << \"]\" << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nvar threeSum = function(nums) {\n    // Write your code here\n    return [];\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/nums = (\\[.*?\\])/);\n        if(!match) return;\n        const nums = JSON.parse(match[1]);\n        const result = threeSum(nums);\n        console.log(JSON.stringify(result));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Reverse Linked List',
    4,
    'Easy',
    'Given the head of a singly linked list, reverse the list, and return the reversed list.',
    '[
        {"input": "head = [1,2,3,4,5]", "expected_output": "[5,4,3,2,1]"},
        {"input": "head = [1,2]", "expected_output": "[2,1]"},
        {"input": "head = []", "expected_output": "[]"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n\nusing namespace std;\n\nstruct ListNode {\n    int val;\n    ListNode *next;\n    ListNode() : val(0), next(nullptr) {}\n    ListNode(int x) : val(x), next(nullptr) {}\n    ListNode(int x, ListNode *next) : val(x), next(next) {}\n};\n\nclass Solution {\npublic:\n    ListNode* reverseList(ListNode* head) {\n        // Write your code here\n        return nullptr;\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    ListNode dummy;\n    ListNode* curr = &dummy;\n    if (!arrayStr.empty()) {\n        stringstream ss(arrayStr);\n        string token;\n        while (getline(ss, token, '','')) {\n            curr->next = new ListNode(stoi(token));\n            curr = curr->next;\n        }\n    }\n    Solution sol;\n    ListNode* res = sol.reverseList(dummy.next);\n    cout << \"[\";\n    while (res) {\n        cout << res->val << (res->next ? \",\" : \"\");\n        res = res->next;\n    }\n    cout << \"]\" << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nfunction ListNode(val, next) {\n    this.val = (val===undefined ? 0 : val)\n    this.next = (next===undefined ? null : next)\n}\n\nvar reverseList = function(head) {\n    // Write your code here\n    return null;\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/head = (\\[.*?\\])/);\n        if(!match) return;\n        const arr = JSON.parse(match[1]);\n        let dummy = new ListNode();\n        let curr = dummy;\n        for(let val of arr) {\n            curr.next = new ListNode(val);\n            curr = curr.next;\n        }\n        let res = reverseList(dummy.next);\n        let out = [];\n        while(res) { out.push(res.val); res = res.next; }\n        console.log(JSON.stringify(out));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Linked List Cycle',
    4,
    'Easy',
    'Given head, the head of a linked list, determine if the linked list has a cycle in it. (pos represents the index of the node that tail connects to).',
    '[
        {"input": "head = [3,2,0,-4], pos = 1", "expected_output": "true"},
        {"input": "head = [1,2], pos = 0", "expected_output": "true"},
        {"input": "head = [1], pos = -1", "expected_output": "false"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n\nusing namespace std;\n\nstruct ListNode {\n    int val;\n    ListNode *next;\n    ListNode(int x) : val(x), next(NULL) {}\n};\n\nclass Solution {\npublic:\n    bool hasCycle(ListNode *head) {\n        // Write your code here\n        return false;\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    size_t posStart = input.find(\"pos = \");\n    int pos = -1;\n    if(posStart != string::npos) pos = stoi(input.substr(posStart + 6));\n    \n    ListNode dummy(0);\n    ListNode* curr = &dummy;\n    vector<ListNode*> nodes;\n    if (!arrayStr.empty()) {\n        stringstream ss(arrayStr);\n        string token;\n        while (getline(ss, token, '','')) {\n            ListNode* n = new ListNode(stoi(token));\n            nodes.push_back(n);\n            curr->next = n;\n            curr = curr->next;\n        }\n    }\n    if(pos >= 0 && pos < nodes.size()) {\n        curr->next = nodes[pos];\n    }\n    \n    Solution sol;\n    bool res = sol.hasCycle(dummy.next);\n    cout << (res ? \"true\" : \"false\") << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nfunction ListNode(val) {\n    this.val = val;\n    this.next = null;\n}\n\nvar hasCycle = function(head) {\n    // Write your code here\n    return false;\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/head = (\\[.*?\\])/);\n        const posMatch = input.match(/pos = (-?\\d+)/);\n        if(!match) return;\n        const arr = JSON.parse(match[1]);\n        const pos = posMatch ? parseInt(posMatch[1]) : -1;\n        \n        let dummy = new ListNode(0);\n        let curr = dummy;\n        let nodes = [];\n        for(let val of arr) {\n            let n = new ListNode(val);\n            nodes.push(n);\n            curr.next = n;\n            curr = curr.next;\n        }\n        if(pos >= 0 && pos < nodes.length) {\n            curr.next = nodes[pos];\n        }\n        let res = hasCycle(dummy.next);\n        console.log(res ? \"true\" : \"false\");\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Daily Temperatures',
    5,
    'Medium',
    'Given an array of integers temperatures represents the daily temperatures, return an array answer such that answer[i] is the number of days you have to wait after the ith day to get a warmer temperature.',
    '[
        {"input": "temperatures = [73,74,75,71,69,72,76,73]", "expected_output": "[1,1,4,2,1,1,0,0]"},
        {"input": "temperatures = [30,40,50,60]", "expected_output": "[1,1,1,0]"},
        {"input": "temperatures = [30,60,90]", "expected_output": "[1,1,0]"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<int> dailyTemperatures(vector<int>& temperatures) {\n        // Write your code here\n        return {};\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    vector<int> temps;\n    if (!arrayStr.empty()) {\n        stringstream ss(arrayStr);\n        string token;\n        while (getline(ss, token, '','')) {\n            temps.push_back(stoi(token));\n        }\n    }\n    Solution sol;\n    vector<int> res = sol.dailyTemperatures(temps);\n    cout << \"[\";\n    for(size_t i = 0; i < res.size(); ++i) {\n        cout << res[i] << (i == res.size()-1 ? \"\" : \",\");\n    }\n    cout << \"]\" << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nvar dailyTemperatures = function(temperatures) {\n    // Write your code here\n    return [];\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/temperatures = (\\[.*?\\])/);\n        if(!match) return;\n        const arr = JSON.parse(match[1]);\n        let res = dailyTemperatures(arr);\n        console.log(JSON.stringify(res));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Sliding Window Maximum',
    6,
    'Hard',
    'You are given an array of integers nums, there is a sliding window of size k which is moving from the very left of the array to the very right. Return the max sliding window.',
    '[
        {"input": "nums = [1,3,-1,-3,5,3,6,7], k = 3", "expected_output": "[3,3,5,5,6,7]"},
        {"input": "nums = [1], k = 1", "expected_output": "[1]"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<int> maxSlidingWindow(vector<int>& nums, int k) {\n        // Write your code here\n        return {};\n    }\n};\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    vector<int> nums;\n    if (!arrayStr.empty()) {\n        stringstream ss(arrayStr);\n        string token;\n        while (getline(ss, token, '','')) {\n            nums.push_back(stoi(token));\n        }\n    }\n    size_t kStart = input.find(\"k = \");\n    int k = stoi(input.substr(kStart + 4));\n    Solution sol;\n    vector<int> res = sol.maxSlidingWindow(nums, k);\n    cout << \"[\";\n    for(size_t i = 0; i < res.size(); ++i) {\n        cout << res[i] << (i == res.size()-1 ? \"\" : \",\");\n    }\n    cout << \"]\" << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nvar maxSlidingWindow = function(nums, k) {\n    // Write your code here\n    return [];\n};\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/nums = (\\[.*?\\])/);\n        const kMatch = input.match(/k = (\\d+)/);\n        if(!match || !kMatch) return;\n        const arr = JSON.parse(match[1]);\n        const k = parseInt(kMatch[1]);\n        let res = maxSlidingWindow(arr, k);\n        console.log(JSON.stringify(res));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Invert Binary Tree',
    7,
    'Easy',
    'Given the root of a binary tree, invert the tree, and return its root.',
    '[
        {"input": "root = [4,2,7,1,3,6,9]", "expected_output": "[4,7,2,9,6,3,1]"},
        {"input": "root = [2,1,3]", "expected_output": "[2,3,1]"},
        {"input": "root = []", "expected_output": "[]"}
    ]'::jsonb,
    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n#include <queue>\n\nusing namespace std;\n\nstruct TreeNode {\n    int val;\n    TreeNode *left;\n    TreeNode *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n};\n\nclass Solution {\npublic:\n    TreeNode* invertTree(TreeNode* root) {\n        // Write your code here\n        return nullptr;\n    }\n};\n\nTreeNode* parseTree(string arrayStr) {\n    if(arrayStr.empty()) return nullptr;\n    vector<string> parts;\n    stringstream ss(arrayStr);\n    string token;\n    while (getline(ss, token, '','')) parts.push_back(token);\n    if(parts.empty() || parts[0] == \"null\") return nullptr;\n    \n    TreeNode* root = new TreeNode(stoi(parts[0]));\n    queue<TreeNode*> q;\n    q.push(root);\n    int i = 1;\n    while(!q.empty() && i < parts.size()) {\n        TreeNode* curr = q.front(); q.pop();\n        if(i < parts.size() && parts[i] != \"null\") {\n            curr->left = new TreeNode(stoi(parts[i]));\n            q.push(curr->left);\n        }\n        i++;\n        if(i < parts.size() && parts[i] != \"null\") {\n            curr->right = new TreeNode(stoi(parts[i]));\n            q.push(curr->right);\n        }\n        i++;\n    }\n    return root;\n}\n\nstring treeToString(TreeNode* root) {\n    if(!root) return \"[]\";\n    string res = \"[\";\n    queue<TreeNode*> q;\n    q.push(root);\n    vector<string> parts;\n    while(!q.empty()) {\n        TreeNode* node = q.front(); q.pop();\n        if(!node) {\n            parts.push_back(\"null\");\n        } else {\n            parts.push_back(to_string(node->val));\n            q.push(node->left);\n            q.push(node->right);\n        }\n    }\n    while(!parts.empty() && parts.back() == \"null\") parts.pop_back();\n    for(size_t i = 0; i < parts.size(); ++i) {\n        res += parts[i] + (i == parts.size()-1 ? \"\" : \",\");\n    }\n    res += \"]\";\n    return res;\n}\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    // remove spaces and quotes if any\n    string cleanStr = \"\";\n    for(char c : arrayStr) { if(c != '' '' && c != ''\"'') cleanStr += c; }\n    TreeNode* root = parseTree(cleanStr);\n    Solution sol;\n    TreeNode* res = sol.invertTree(root);\n    cout << treeToString(res) << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nfunction TreeNode(val, left, right) {\n    this.val = (val===undefined ? 0 : val)\n    this.left = (left===undefined ? null : left)\n    this.right = (right===undefined ? null : right)\n}\n\nvar invertTree = function(root) {\n    // Write your code here\n    return null;\n};\n\nfunction parseTree(arr) {\n    if(!arr || arr.length === 0) return null;\n    let root = new TreeNode(arr[0]);\n    let queue = [root];\n    let i = 1;\n    while(queue.length > 0 && i < arr.length) {\n        let curr = queue.shift();\n        if(i < arr.length && arr[i] !== null) {\n            curr.left = new TreeNode(arr[i]);\n            queue.push(curr.left);\n        }\n        i++;\n        if(i < arr.length && arr[i] !== null) {\n            curr.right = new TreeNode(arr[i]);\n            queue.push(curr.right);\n        }\n        i++;\n    }\n    return root;\n}\n\nfunction treeToArray(root) {\n    if(!root) return [];\n    let res = [];\n    let queue = [root];\n    while(queue.length > 0) {\n        let node = queue.shift();\n        if(!node) {\n            res.push(null);\n        } else {\n            res.push(node.val);\n            queue.push(node.left);\n            queue.push(node.right);\n        }\n    }\n    while(res.length > 0 && res[res.length-1] === null) res.pop();\n    return res;\n}\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/root = (\\[.*?\\])/);\n        if(!match) return;\n        // convert to replace nulls\n        let arrStr = match[1].replace(/null/g, ''\"null\"'');\n        const arr = JSON.parse(arrStr).map(x => x === \"null\" ? null : x);\n        let root = parseTree(arr);\n        let res = invertTree(root);\n        let out = treeToArray(res);\n        console.log(JSON.stringify(out));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
),
(
    'Binary Tree Level Order Traversal',
