    '{"cpp":"#include <iostream>\n#include <vector>\n#include <string>\n#include <sstream>\n#include <queue>\n\nusing namespace std;\n\nstruct TreeNode {\n    int val;\n    TreeNode *left;\n    TreeNode *right;\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n};\n\nclass Solution {\npublic:\n    vector<vector<int>> levelOrder(TreeNode* root) {\n        // Write your code here\n        return {};\n    }\n};\n\nTreeNode* parseTree(string arrayStr) {\n    if(arrayStr.empty()) return nullptr;\n    vector<string> parts;\n    stringstream ss(arrayStr);\n    string token;\n    while (getline(ss, token, '','')) parts.push_back(token);\n    if(parts.empty() || parts[0] == \"null\") return nullptr;\n    \n    TreeNode* root = new TreeNode(stoi(parts[0]));\n    queue<TreeNode*> q;\n    q.push(root);\n    int i = 1;\n    while(!q.empty() && i < parts.size()) {\n        TreeNode* curr = q.front(); q.pop();\n        if(i < parts.size() && parts[i] != \"null\") {\n            curr->left = new TreeNode(stoi(parts[i]));\n            q.push(curr->left);\n        }\n        i++;\n        if(i < parts.size() && parts[i] != \"null\") {\n            curr->right = new TreeNode(stoi(parts[i]));\n            q.push(curr->right);\n        }\n        i++;\n    }\n    return root;\n}\n\nint main() {\n    string input;\n    if (!getline(cin, input)) return 0;\n    size_t bracketStart = input.find(''['');\n    size_t bracketEnd = input.find('']'');\n    string arrayStr = input.substr(bracketStart + 1, bracketEnd - bracketStart - 1);\n    string cleanStr = \"\";\n    for(char c : arrayStr) { if(c != '' '' && c != ''\"'') cleanStr += c; }\n    TreeNode* root = parseTree(cleanStr);\n    Solution sol;\n    vector<vector<int>> res = sol.levelOrder(root);\n    cout << \"[\";\n    for (size_t i = 0; i < res.size(); ++i) {\n        cout << \"[\";\n        for (size_t j = 0; j < res[i].size(); ++j) {\n            cout << res[i][j] << (j == res[i].size() - 1 ? \"\" : \",\");\n        }\n        cout << \"]\" << (i == res.size() - 1 ? \"\" : \",\");\n    }\n    cout << \"]\" << endl;\n    return 0;\n}","javascript":"const fs = require(''fs'');\n\nfunction TreeNode(val, left, right) {\n    this.val = (val===undefined ? 0 : val)\n    this.left = (left===undefined ? null : left)\n    this.right = (right===undefined ? null : right)\n}\n\nvar levelOrder = function(root) {\n    // Write your code here\n    return [];\n};\n\nfunction parseTree(arr) {\n    if(!arr || arr.length === 0) return null;\n    let root = new TreeNode(arr[0]);\n    let queue = [root];\n    let i = 1;\n    while(queue.length > 0 && i < arr.length) {\n        let curr = queue.shift();\n        if(i < arr.length && arr[i] !== null) {\n            curr.left = new TreeNode(arr[i]);\n            queue.push(curr.left);\n        }\n        i++;\n        if(i < arr.length && arr[i] !== null) {\n            curr.right = new TreeNode(arr[i]);\n            queue.push(curr.right);\n        }\n        i++;\n    }\n    return root;\n}\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/root = (\\[.*?\\])/);\n        if(!match) return;\n        let arrStr = match[1].replace(/null/g, ''\"null\"'');\n        const arr = JSON.parse(arrStr).map(x => x === \"null\" ? null : x);\n        let root = parseTree(arr);\n        let res = levelOrder(root);\n        console.log(JSON.stringify(res));\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
