t = (right===undefined ? null : right)\n}\n\nvar isValidBST = function(root) {\n    // Write your code here\n    return false;\n};\n\nfunction parseTree(arr) {\n    if(!arr || arr.length === 0) return null;\n    let root = new TreeNode(arr[0]);\n    let queue = [root];\n    let i = 1;\n    while(queue.length > 0 && i < arr.length) {\n        let curr = queue.shift();\n        if(i < arr.length && arr[i] !== null) {\n            curr.left = new TreeNode(arr[i]);\n            queue.push(curr.left);\n        }\n        i++;\n        if(i < arr.length && arr[i] !== null) {\n            curr.right = new TreeNode(arr[i]);\n            queue.push(curr.right);\n        }\n        i++;\n    }\n    return root;\n}\n\nfunction main() {\n    try {\n        const input = fs.readFileSync(''/dev/stdin'', ''utf-8'').trim();\n        if (!input) return;\n        const match = input.match(/root = (\\[.*?\\])/);\n        if(!match) return;\n        let arrStr = match[1].replace(/null/g, ''\"null\"'');\n        const arr = JSON.parse(arrStr).map(x => x === \"null\" ? null : x);\n        let root = parseTree(arr);\n        let res = isValidBST(root);\n        console.log(res ? \"true\" : \"false\");\n    } catch(e) {}\n}\n\nmain();"}'::jsonb
